// Helper: get extended exercises by category
export function getExercisesByCategory(category: string): ExtendedExercise[] {
  return exercisesExtended.filter((e) => e.category === category);
}

// Helper: get extended exercises by difficulty
export function getExercisesByDifficulty(difficulty: ExtendedExercise["difficulty"]): ExtendedExercise[] {
  return exercisesExtended.filter((e) => e.difficulty === difficulty);
}

// Helper: get an extended exercise by id
export function getExtendedExerciseById(id: string): ExtendedExercise | undefined {
  return exercisesExtended.find((e) => e.id === id);
}

// Helper: list of unique categories
export const extendedCategories: string[] = Array.from(
  new Set(exercisesExtended.map((e) => e.category))
);

// Helper: list of unique related topics
export const extendedRelatedTopics: string[] = Array.from(
  new Set(exercisesExtended.map((e) => e.relatedTopic ?? ""))
);
